using System.ComponentModel;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n­¤öŹ Researching: {topic}\n");

// --- Build the IChatClient through MEAI abstraction ---
var modelId = "gpt-4o-mini-2024-07-18";
IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Register tools ---
var notebook = new Notebook();
var webSearch = new WebSearchTool();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(webSearch.FetchPageAsync),
    AIFunctionFactory.Create(notebook.SaveNote),
    AIFunctionFactory.Create(notebook.GetAllNotes),
};

// --- Create the agent ---
var agentOptions = new ChatClientAgentOptions
{
    Name = "ResearchAgent",
    Description = "An agent that researches topics by searching the web and taking notes.",
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    },
};

var agent = new ChatClientAgent(chatClient, agentOptions, tools: tools);

// --- Run the agent ---
var session = await agent.CreateSessionAsync();

var instructions = $"""
    You are a research assistant. Your goal is to research the following topic 
    and produce a well-organized summary.

    Topic: {topic}

    Follow these steps:
    1. Search the web for information about this topic (2-3 searches with 
       different queries to get broad coverage).
    2. Fetch the most relevant pages to get detailed information.
    3. Save key findings as notes with descriptive titles.
    4. After gathering enough information, retrieve all your notes and produce 
       a final comprehensive summary.

    Be thorough but concise. Cite sources where possible.
    """;

Console.WriteLine("Agent is working...\n");

await foreach (var update in agent.RunStreamingAsync(
    instructions, session))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();

// --- Helpers ---
static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrWhiteSpace(input)
        ? throw new InvalidOperationException("A research topic is required.")
        : input;
}

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------

/// <summary>Searches the web and fetches page content.</summary>
sealed class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        Timeout = TimeSpan.FromSeconds(15),
        DefaultRequestHeaders =
        {
            { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" },
        },
    };

    [Description("Search the web for a query and return a list of result titles, URLs, and snippets.")]
    public async Task<string> SearchAsync(
        [Description("The search query")] string query)
    {
        Console.WriteLine($"  ­¤īÉ Searching: {query}");

        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var html = await Http.GetStringAsync(url);
            var results = ParseSearchResults(html);

            return results.Count == 0
                ? "No results found."
                : string.Join("\n\n", results.Select((r, i) =>
                    $"[{i + 1}] {r.Title}\n    URL: {r.Url}\n    {r.Snippet}"));
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    [Description("Fetch the text content of a web page given its URL.")]
    public async Task<string> FetchPageAsync(
        [Description("The full URL to fetch")] string url)
    {
        Console.WriteLine($"  ­¤ōä Fetching: {url}");

        try
        {
            var html = await Http.GetStringAsync(url);
            var text = StripHtml(html);

            // Limit to ~4000 chars to stay within context budget
            return text.Length > 4000 ? text[..4000] + "\n[...truncated]" : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseSearchResults(string html)
    {
        var results = new List<SearchResult>();
        var linkPattern = "class=\"result__a\"";
        var snippetPattern = "class=\"result__snippet\"";

