 /// <summary>Searches the web and fetches page content.</summary>
 sealed class WebSearchTool
 {
     private static readonly HttpClient Http = new()
     {
         Timeout = TimeSpan.FromSeconds(15),
         DefaultRequestHeaders =
         {
             { "User-Agent", "Mozilla/5.0 (compatible; ResearchAgent/1.0)" },
         },
     };

     [Description("Search the web for a query and return a list of result titles, URLs, and snippets.")]
     public async Task<string> SearchAsync(
         [Description("The search query")] string query)
     {
         Console.WriteLine($"  ­¤īÉ Searching: {query}");

         try
         {
             var encoded = Uri.EscapeDataString(query);
             var url = $"https://html.duckduckgo.com/html/?q={encoded}";
             var html = await Http.GetStringAsync(url);
             var results = ParseSearchResults(html);

             return results.Count == 0
                 ? "No results found."
                 : string.Join("\n\n", results.Select((r, i) =>
                     $"[{i + 1}] {r.Title}\n    URL: {r.Url}\n    {r.Snippet}"));
         }
         catch (Exception ex)
         {
             return $"Search failed: {ex.Message}";
         }
     }

     [Description("Fetch the text content of a web page given its URL.")]
     public async Task<string> FetchPageAsync(
         [Description("The full URL to fetch")] string url)
     {
         Console.WriteLine($"  ­¤ōä Fetching: {url}");

         try
         {
             var html = await Http.GetStringAsync(url);
             var text = StripHtml(html);

             // Limit to ~4000 chars to stay within context budget
             return text.Length > 4000 ? text[..4000] + "\n[...truncated]" : text;
         }
         catch (Exception ex)
         {
             return $"Failed to fetch page: {ex.Message}";
         }
     }

     private static List<SearchResult> ParseSearchResults(string html)
     {
         var results = new List<SearchResult>();
         var linkPattern = "class=\"result__a\"";
         var snippetPattern = "class=\"result__snippet\"";

         var pos = 0;
         while (results.Count < 5)
         {
             var linkIdx = html.IndexOf(linkPattern, pos, StringComparison.Ordinal);
             if (linkIdx < 0) break;

             var hrefIdx = html.LastIndexOf("href=\"", linkIdx, Math.Min(linkIdx, 200), StringComparison.Ordinal);
             var urlValue = "";
             if (hrefIdx >= 0)
             {
                 var start = hrefIdx + 6;
                 var end = html.IndexOf('"', start);
                 if (end > start)
                     urlValue = html[start..end];
             }

             var titleStart = html.IndexOf('>', linkIdx) + 1;
             var titleEnd = html.IndexOf('<', titleStart);
             var title = titleStart > 0 && titleEnd > titleStart
                 ? StripHtml(html[titleStart..titleEnd]).Trim()
                 : "";

             var snippet = "";
             var snippetIdx = html.IndexOf(snippetPattern, linkIdx, StringComparison.Ordinal);
             if (snippetIdx >= 0)
             {
                 var sStart = html.IndexOf('>', snippetIdx) + 1;
                 var sEnd = html.IndexOf("</", sStart, StringComparison.Ordinal);
                 if (sStart > 0 && sEnd > sStart)
                     snippet = StripHtml(html[sStart..sEnd]).Trim();
             }

             if (!string.IsNullOrWhiteSpace(title) && !string.IsNullOrWhiteSpace(urlValue))
             {
                 // DuckDuckGo wraps URLs in a redirect; extract the actual URL
                 if (urlValue.Contains("uddg="))
                 {
                     var uddgIdx = urlValue.IndexOf("uddg=", StringComparison.Ordinal) + 5;
                     var ampIdx = urlValue.IndexOf('&', uddgIdx);
                     urlValue = Uri.UnescapeDataString(
                         ampIdx > 0 ? urlValue[uddgIdx..ampIdx] : urlValue[uddgIdx..]);
                 }

                 results.Add(new SearchResult(title, urlValue, snippet));
             }

             pos = linkIdx + linkPattern.Length;
         }

         return results;
     }

     private static string StripHtml(string html)
     {
         // Remove script/style blocks
         var text = System.Text.RegularExpressions.Regex.Replace(
             html, @"<(script|style)[^>]*>.*?</\1>", "", 
             System.Text.RegularExpressions.RegexOptions.Singleline |
             System.Text.RegularExpressions.RegexOptions.IgnoreCase);
         // Remove tags
         text = System.Text.RegularExpressions.Regex.Replace(text, @"<[^>]+>", " ");
         // Decode common entities
         text = System.Net.WebUtility.HtmlDecode(text);
         // Collapse whitespace
         text = System.Text.RegularExpressions.Regex.Replace(text, @"\s+", " ");
         return text.Trim();
     }

     private record SearchResult(string Title, string Url, string Snippet);
 }

 /// <summary>In-memory notebook for the agent to store research findings.</summary>
