 {
     private readonly List<Note> _notes = [];

     [Description("Save a research note with a title and content. Use this to record key findings.")]
     public string SaveNote(
         [Description("Short descriptive title for the note")] string title,
         [Description("The note content with facts, data, or quotes")] string content)
     {
         _notes.Add(new Note(title, content));
         Console.WriteLine($"  ­¤ōØ Note saved: {title}");
         return $"Note '{title}' saved successfully. You now have {_notes.Count} note(s).";
     }

     [Description("Retrieve all saved research notes.")]
     public string GetAllNotes()
     {
         if (_notes.Count == 0)
             return "No notes saved yet.";

         return string.Join("\n\n", _notes.Select((n, i) =>
             $"--- Note {i + 1}: {n.Title} ---\n{n.Content}"));
     }

     private record Note(string Title, string Content);
 }

